import requests
import os

def upload_multipart_file(url, file_path, file_field_name='file', form_data=None, headers=None):
    if not os.path.exists(file_path):
        return None

    file_name = os.path.basename(file_path)

    try:
        with open(file_path, 'rb') as file_handle:
            files = {file_field_name: (file_name, file_handle)}

            response = requests.post(url, files=files, data=form_data, headers=headers)
            response.raise_for_status()
            return response
    except requests.exceptions.RequestException:
        return None
    except FileNotFoundError:
        return None
    except Exception:
        return None
